"use client";

import { useEffect, useRef, useState } from "react";
import { createPortal } from "react-dom";
import { motion, AnimatePresence, Variants } from "motion/react";

interface SectionLink {
  id: string;
  label: string;
  targetIds?: string[];
}

export default function CaseStudySidebar({ links }: { links: SectionLink[] }) {
  const [activeId, setActiveId] = useState<string>("");
  const [isVisible, setIsVisible] = useState(false);
  const [mounted, setMounted] = useState(false);
  const visibleSections = useRef(new Map<string, number>());

  useEffect(() => {
    setMounted(true);
    const handleScroll = () => {
      if (window.scrollY > 80) {
        setIsVisible(true);
      } else {
        setIsVisible(false);
      }
    };

    window.addEventListener("scroll", handleScroll);
    handleScroll();

    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            visibleSections.current.set(entry.target.id, entry.intersectionRatio);
          } else {
            visibleSections.current.delete(entry.target.id);
          }
        });

        if (visibleSections.current.size > 0) {
          let maxRatio = -1;
          let maxId = "";

          visibleSections.current.forEach((ratio, id) => {
            if (ratio > maxRatio) {
              maxRatio = ratio;
              maxId = id;
            }
          });

          if (maxId) {
            setActiveId(maxId);
          }
        }
      },
      {
        rootMargin: "-20% 0px -60% 0px",
        threshold: [0, 0.25, 0.5, 0.75, 1],
      }
    );

    links.forEach((link) => {
      const idsToObserve = link.targetIds || [link.id];
      idsToObserve.forEach((id) => {
        const element = document.getElementById(id);
        if (element) {
          observer.observe(element);
        }
      });
    });

    return () => observer.disconnect();
  }, [links]);

  const scrollToSection = (id: string) => {
    const target = document.getElementById(id);
    if (!target) {
      return;
    }

    const yOffset = 120;
    const top = target.getBoundingClientRect().top + window.scrollY - yOffset;
    window.scrollTo({ top, behavior: "smooth" });
    window.history.replaceState(null, "", `#${id}`);
  };

  if (!mounted) return null;

  const containerVariants: Variants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.04,
        staggerDirection: 1,
      },
    },
    exit: {
      opacity: 0,
      transition: {
        staggerChildren: 0.03,
        staggerDirection: -1,
        when: "afterChildren",
      },
    },
  };

  const itemVariants: Variants = {
    hidden: { 
      opacity: 0, 
      x: -24, 
      filter: "blur(4px)" 
    },
    visible: { 
      opacity: 1, 
      x: 0, 
      filter: "blur(0px)",
      transition: {
        type: "spring" as const,
        stiffness: 240,
        damping: 22,
        mass: 0.8
      }
    },
    exit: { 
      opacity: 0, 
      x: -24, 
      filter: "blur(4px)",
      transition: {
        duration: 0.2
      }
    },
  };

  return createPortal(
    <aside
      className={`fixed left-[40px] top-[120px] z-[60] hidden w-48 shrink-0 flex-col gap-10 md:flex fixed-preview-portal`}
    >
      <AnimatePresence mode="wait">
        {isVisible && (
          <motion.nav
            key="sidebar-nav"
            variants={containerVariants}
            initial="hidden"
            animate="visible"
            exit="exit"
            className="flex flex-col gap-[12px]"
          >
            {links.map((link) => {
              const idsToCheck = link.targetIds || [link.id];
              const isActive = idsToCheck.includes(activeId);

              return (
                <motion.a
                  key={link.id}
                  href={`#${link.id}`}
                  variants={itemVariants}
                  whileHover={{ x: 4, transition: { type: "spring" as const, stiffness: 400, damping: 20 } }}
                  onClick={(event) => {
                    event.preventDefault();
                    scrollToSection(link.id);
                  }}
                  className={`text-[14px] font-normal transition-colors duration-200 block ${
                    isActive ? "text-foreground" : "text-muted-foreground hover:text-foreground"
                  }`}
                >
                  {link.label}
                </motion.a>
              );
            })}
          </motion.nav>
        )}
      </AnimatePresence>
    </aside>,
    document.body
  );
}

"use client";

import { useEffect, useRef, useState } from "react";
import gsap from "gsap";
import { useGSAP } from "@gsap/react";

export default function CustomCursor() {
    const cursorRef = useRef<HTMLDivElement>(null);
    const [cursorType, setCursorType] = useState<"default" | "copy" | "copied" | "pointer" | "case-study" | "confidential">("default");
    const isMobile = useRef(false);

    const resetTimeoutRef = useRef<NodeJS.Timeout | null>(null);

    useEffect(() => {
        if (window.matchMedia("(pointer: coarse)").matches) {
            isMobile.current = true;
            return;
        }

        const handleCursorChange = (e: any) => {
            if (resetTimeoutRef.current) clearTimeout(resetTimeoutRef.current);
            setCursorType(e.detail);
        };

        const handleMouseOver = (e: MouseEvent) => {
            const target = e.target as HTMLElement;
            const cursorAttr = target.closest("[data-cursor]")?.getAttribute("data-cursor");
            
            if (cursorType === "copied") return; 

            if (cursorAttr) {
                if (resetTimeoutRef.current) clearTimeout(resetTimeoutRef.current);
                setCursorType(cursorAttr as any);
            } else {
                if (resetTimeoutRef.current) clearTimeout(resetTimeoutRef.current);
                resetTimeoutRef.current = setTimeout(() => {
                    setCursorType("default");
                }, 50);
            }
        };

        window.addEventListener("cursor-change", handleCursorChange);
        window.addEventListener("mouseover", handleMouseOver);
        
        return () => {
            window.removeEventListener("cursor-change", handleCursorChange);
            window.removeEventListener("mouseover", handleMouseOver);
        };
    }, [cursorType]);

    useGSAP(() => {
        if (isMobile.current || !cursorRef.current) {
            if (cursorRef.current) gsap.set(cursorRef.current, { display: "none" });
            return;
        }

        gsap.set(cursorRef.current, { autoAlpha: 0, xPercent: -50, yPercent: -50 });

        const xTo = gsap.quickTo(cursorRef.current, "x", { duration: 0.15, ease: "power2.out" });
        const yTo = gsap.quickTo(cursorRef.current, "y", { duration: 0.15, ease: "power2.out" });

        let isVisible = false;

        const handleMouseMove = (e: MouseEvent) => {
            if (!isVisible) {
                gsap.to(cursorRef.current, { autoAlpha: 1, duration: 0.3 });
                isVisible = true;
            }
            xTo(e.clientX);
            yTo(e.clientY);
        };

        const handleMouseDown = () => {
            // Only scale down if we hold for more than 100ms
            gsap.to(cursorRef.current, { 
                scale: 0.8, 
                duration: 0.15, 
                delay: 0.1, // This mimics the 'extended period' logic
                ease: "power2.out",
                overwrite: "auto" 
            });
        };
        
        const handleMouseUp = () => {
            // Immediately snap back to 1
            gsap.to(cursorRef.current, { 
                scale: 1, 
                duration: 0.15, 
                delay: 0, 
                ease: "power4.out", 
                overwrite: "auto" 
            });
        };

        window.addEventListener("mousemove", handleMouseMove);
        window.addEventListener("mousedown", handleMouseDown);
        window.addEventListener("mouseup", handleMouseUp);

        return () => {
            window.removeEventListener("mousemove", handleMouseMove);
            window.removeEventListener("mousedown", handleMouseDown);
            window.removeEventListener("mouseup", handleMouseUp);
        };
    }, { scope: cursorRef });

    useGSAP(() => {
        if (!cursorRef.current) return;

        if (cursorType === "copy") {
            gsap.to(cursorRef.current, {
                mixBlendMode: "normal",
                width: 100,
                height: 40,
                borderRadius: "20px",
                backgroundColor: "#ffffff",
                color: "#000000",
                duration: 0.4,
                ease: "elastic.out(1, 0.82)"
            });
        } else if (cursorType === "copied") {
            gsap.to(cursorRef.current, {
                mixBlendMode: "normal",
                backgroundColor: "#22c55e",
                color: "#ffffff",
                duration: 0.2,
            });
            gsap.to(cursorRef.current, {
                scale: 1.1,
                duration: 0.1,
                yoyo: true,
                repeat: 1
            });
        } else if (cursorType === "case-study" || cursorType === "confidential") {
            gsap.to(cursorRef.current, {
                mixBlendMode: "normal",
                width: cursorType === "case-study" ? 160 : 120,
                height: 40,
                borderRadius: "20px",
                backgroundColor: "#ffffff",
                color: "#000000",
                duration: 0.4,
                ease: "elastic.out(1, 0.82)"
            });
        } else if (cursorType === "pointer") {
            gsap.to(cursorRef.current, {
                width: 8,
                height: 8,
                borderRadius: "100%",
                backgroundColor: "white",
                mixBlendMode: "difference",
                color: "#ffffff",
                duration: 0.3,
                ease: "power2.out"
            });
        } else {
            gsap.to(cursorRef.current, {
                width: 16,
                height: 16,
                borderRadius: "100%",
                backgroundColor: "white",
                mixBlendMode: "difference",
                color: "#ffffff",
                duration: 0.4,
                ease: "power3.out"
            });
        }
    }, { dependencies: [cursorType] });

    return (
        <div
            ref={cursorRef}
            className="hidden lg:flex fixed top-0 left-0 items-center justify-center pointer-events-none z-[9999] overflow-hidden whitespace-nowrap tracking-tight font-normal opacity-0"
            style={{ willChange: "transform, width, height, border-radius, background-color" }}
        >
            <span className={`transition-opacity duration-300 uppercase text-[10px] font-normal tracking-wider ${cursorType === "copy" ? "opacity-100" : "opacity-0 invisible"}`}>
                Copy Email
            </span>
            <span className={`absolute transition-opacity duration-300 uppercase text-[10px] font-normal tracking-wider ${cursorType === "copied" ? "opacity-100" : "opacity-0 invisible"}`}>
                Copied!
            </span>
            <span className={`absolute transition-opacity duration-300 text-[14px] ${cursorType === "case-study" ? "opacity-100" : "opacity-0 invisible"}`}>
                View Case Study
            </span>
            <span className={`absolute transition-opacity duration-300 text-[14px] ${cursorType === "confidential" ? "opacity-100" : "opacity-0 invisible"}`}>
                Confidential
            </span>
            <div className={`transition-opacity duration-300 ${cursorType === "pointer" ? "opacity-100" : "opacity-0 invisible"}`}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="text-white mix-blend-difference">
                   <path d="M10 13V6a2 2 0 0 1 4 0v7" />
                   <path d="M18 11.5a2 2 0 0 1 4 0V20a5 5 0 0 1-5 5H7a5 5 0 0 1-5-5v-2" />
                   <path d="M21 11V7.5a2 2 0 0 1 4 0V11" />
                   <path d="M7 10.5a2 2 0 0 0-4 0v3.5" />
                </svg>
            </div>
        </div>
    );
}

